const dyeProfilesB: FiberProfile[] = [
  p({ id: "bloodroot", name: "Bloodroot", image: "https://res.cloudinary.com/dawxvzlte/image/upload/v1771619459/atlas/g3n0arfxdkuhbfyowilc.jpg", category: "dye", subtitle: "Root Dye, Native American Red-Orange", about: "Bloodroot (Sanguinaria canadensis) is a North American woodland plant whose rhizome contains a vivid red-orange pigment called sanguinarine that bleeds dramatically when the root is cut — hence the common name. Indigenous peoples of eastern North America used bloodroot extensively for dyeing porcupine quills, baskets, and clothing, as well as for body paint and medicinal purposes. The dye produces bright orange-red with alum mordant and shifts to rose-pink on protein fibers. However, bloodroot is now listed as 'at risk' in several states due to over-harvesting, and responsible dyers either cultivate their own or use alternatives. The plant is a spring ephemeral that blooms before forest canopy leafs out, producing a single white flower wrapped in a distinctive lobed leaf.", tags: ["Root", "Red-Orange", "Indigenous", "Woodland", "At-Risk"], regions: ["Eastern North America"], seasonality: "Root Harvested Spring/Autumn", priceRange: { raw: "$30.00 – $80.00 / kg", minUSD: 30.0, maxUSD: 80.0, unit: "kg" }, translationCount: 3, typicalMOQ: { quantity: 1, unit: "kg" }, leadTime: { minWeeks: 8, maxWeeks: 14 }, profilePills: { scientificName: "Sanguinaria Canadensis", plantPart: "Root", handFeel: "N/A", fiberType: "Plant Dye", era: "Indigenous", origin: "North America" }, seeAlso: [{ id: "madder" }, { id: "osage-orange" }, { id: "black-walnut" }] }),
  p({ id: "brazilwood", name: "Brazilwood", image: "https://res.cloudinary.com/dawxvzlte/image/upload/v1771619466/atlas/thzrkdgz1ouf87vvovfx.jpg", category: "dye", subtitle: "Tropical Heartwood, Imperial Red", about: "Brazilwood (Paubrasilia echinata) is so valuable for its red dye that the nation of Brazil was named after it — Portuguese traders called the tree 'pau-brasil' (ember wood) for the fiery red color of its heartwood. The brazilin pigment oxidizes to brazilein upon extraction, producing reds, pinks, and purples that rivaled cochineal and madder in European textile markets. Exploitation was so intense during the colonial era that the species is now endangered and protected under CITES — Brazil's first economic resource became one of its most threatened. The wood was also prized for violin bows (the finest are still called 'pernambuco'), creating a secondary demand that continues to threaten wild populations. Today brazilwood dye is used only by artisan dyers working with sustainably cultivated trees, and synthetic alternatives have replaced it in all commercial applications.", tags: ["Heartwood", "Red", "Colonial", "Endangered", "Historic"], regions: ["Brazil (Atlantic Forest)"], seasonality: "Harvested Year-Round (Protected)", priceRange: { raw: "$40.00 – $100.00 / kg", minUSD: 40.0, maxUSD: 100.0, unit: "kg" }, translationCount: 6, typicalMOQ: { quantity: 2, unit: "kg" }, leadTime: { minWeeks: 12, maxWeeks: 20 }, profilePills: { scientificName: "Paubrasilia Echinata", plantPart: "Heartwood", handFeel: "N/A", fiberType: "Wood Dye", era: "~1500s", origin: "Brazil" }, seeAlso: [{ id: "logwood" }, { id: "madder" }, { id: "cochineal" }] }),
  p({ id: "fustic", name: "Fustic", image: "https://res.cloudinary.com/dawxvzlte/image/upload/v1771619471/atlas/ptcgzd5tursqrkk870ke.jpg", category: "dye", subtitle: "Caribbean Heartwood, Warm Yellow-Gold", about: "Old fustic (Maclura tinctoria) heartwood produces a strong, lightfast yellow to golden-brown dye thanks to the flavonoid morin, making it one of the most important yellow dyes of the colonial era. Spanish and Portuguese traders exported vast quantities of fustic from the Caribbean and Central America to European dye houses, where it was used alone for yellows or combined with indigo for greens. The wood is closely related to osage orange (Maclura pomifera) and produces similar colors, though fustic generally yields warmer, more golden tones. 'Young fustic' (Cotinus coggygria / smoke tree) is an entirely different plant that produces more olive-yellow colors — the two should not be confused despite their shared name. Fustic dye is still valued by artisan dyers for its excellent lightfastness and compatibility with all fiber types.", tags: ["Heartwood", "Yellow", "Colonial", "Lightfast", "Morin"], regions: ["Caribbean", "Central America", "South America"], seasonality: "Harvested Year-Round", priceRange: { raw: "$10.00 – $25.00 / kg (chips)", minUSD: 10.0, maxUSD: 25.0, unit: "kg" }, translationCount: 4, typicalMOQ: { quantity: 5, unit: "kg" }, leadTime: { minWeeks: 6, maxWeeks: 10 }, profilePills: { scientificName: "Maclura Tinctoria", plantPart: "Heartwood", handFeel: "N/A", fiberType: "Wood Dye", era: "~1500s", origin: "Caribbean" }, seeAlso: [{ id: "logwood" }, { id: "osage-orange" }, { id: "weld" }] }),
  p({ id: "oak-bark", name: "Oak Bark", image: "https://res.cloudinary.com/dawxvzlte/image/upload/v1771619477/atlas/harp1wsaiotmiftvwou4.jpg", category: "dye", subtitle: "Bark Tannin, Warm Browns & Tanning Agent", about: "Oak bark is one of the oldest natural dye and tanning materials known, producing warm browns, tans, and honey colors from the tannin-rich inner bark of various Quercus species. The same tannins that color textiles also cross-link collagen proteins in animal hide, making oak bark the foundation of European leather tanning for over 2,000 years — 'tanning' itself derives from the Celtic word for oak. As a textile dye, oak bark is substantive (no mordant needed) and produces colors that improve with age, developing richer, more complex tones over time. Different oak species yield different hues: English oak (Q. robur) produces golden-brown, while red oak (Q. rubra) gives pinker tones. Oak bark is harvested in spring when sap is rising and the bark peels most easily from the trunk.", tags: ["Bark", "Tannin", "Brown", "Tanning", "Ancient"], regions: ["Europe", "North America", "Asia"], seasonality: "Bark Harvested Spring", priceRange: { raw: "$3.00 – $10.00 / kg", minUSD: 3.0, maxUSD: 10.0, unit: "kg" }, translationCount: 8, typicalMOQ: { quantity: 10, unit: "kg" }, leadTime: { minWeeks: 4, maxWeeks: 8 }, profilePills: { scientificName: "Quercus Spp.", plantPart: "Bark", handFeel: "N/A", fiberType: "Bark Dye", era: "Ancient", origin: "Europe" }, seeAlso: [{ id: "black-walnut" }, { id: "cutch" }, { id: "oak-galls" }] }),
  p({ id: "alder", name: "Alder", image: "https://res.cloudinary.com/dawxvzlte/image/upload/v1771619478/atlas/i8g9l6klvx34ab7t7ioz.jpg", category: "dye", subtitle: "Bark Dye, Orange-Red Without Mordant", about: "Red alder (Alnus rubra) bark produces an intense orange-red to rust-brown dye that requires no mordant — one of the few natural dyes that achieves strong color through tannin-based direct bonding. Indigenous peoples of the Pacific Northwest coast used alder bark extensively for dyeing cedar bark textiles, fishing nets, and baskets, as well as for medicinal purposes. The bark contains both tannins and a red pigment that together produce remarkably warm, earthy tones. Freshly harvested inner bark gives the most vivid oranges, while aged or dried bark shifts toward brown. Alder bark dye deepens beautifully with iron afterbath, producing rich chocolate browns and near-blacks. The tree itself is ecologically important as a nitrogen-fixer, enriching the soil in coastal forests from Alaska to California.", tags: ["Bark", "Orange-Red", "No-Mordant", "Indigenous", "Pacific-NW"], regions: ["Pacific Northwest USA", "Canada", "Northern Europe"], seasonality: "Bark Harvested Spring", priceRange: { raw: "$5.00 – $15.00 / kg", minUSD: 5.0, maxUSD: 15.0, unit: "kg" }, translationCount: 4, typicalMOQ: { quantity: 5, unit: "kg" }, leadTime: { minWeeks: 4, maxWeeks: 8 }, profilePills: { scientificName: "Alnus Rubra", plantPart: "Bark", handFeel: "N/A", fiberType: "Bark Dye", era: "Ancient", origin: "Pacific Northwest" }, seeAlso: [{ id: "oak-bark" }, { id: "black-walnut" }, { id: "madder" }] }),
  p({ id: "tea-dye", name: "Tea Dye", image: "https://res.cloudinary.com/dawxvzlte/image/upload/v1771619512/atlas/mwbmnuidoyicclux8exp.jpg", category: "dye", subtitle: "Beverage Dye, Warm Antique Tones", about: "Tea (Camellia sinensis) is one of the most accessible natural dyes, available in nearly every kitchen worldwide and producing warm antique tans, soft browns, and golden ecru tones. The tannins in black tea bond directly to fibers without mordant, making tea dyeing essentially zero-cost and zero-setup — just simmer fabric in strong tea. Crafters and quilters have used tea-staining for decades to give new fabrics a vintage, aged appearance. Different tea types produce different tones: black tea gives warm brown, green tea yields pale gold-green, and rooibos produces warm peach. While not the most lightfast dye, tea's accessibility has made it a gateway to natural dyeing for millions of people. Historically, tea was also used as a tannin source for improving the washfastness of other dyes, particularly on cotton.", tags: ["Beverage", "Tan", "Accessible", "Antique", "Tannin"], regions: ["Global"], seasonality: "Year-Round", priceRange: { raw: "$2.00 – $10.00 / kg", minUSD: 2.0, maxUSD: 10.0, unit: "kg" }, translationCount: 8, typicalMOQ: { quantity: 1, unit: "kg" }, leadTime: { minWeeks: 0, maxWeeks: 0 } /* Immediate */, profilePills: { scientificName: "Camellia Sinensis", plantPart: "Leaf", handFeel: "N/A", fiberType: "Plant Dye", era: "~2700 BCE", origin: "China" }, seeAlso: [{ id: "onion-skins" }, { id: "black-walnut" }, { id: "cutch" }] }),
  p({ id: "dahlia", name: "Dahlia", image: "https://res.cloudinary.com/dawxvzlte/image/upload/v1771619519/atlas/wv5zvamfrlzzy1ojxw21.jpg", category: "dye", subtitle: "Flower Dye, Sunset Oranges & Yellows", about: "Dahlia flowers produce a range of warm yellows, oranges, and burnt golds — with darker-petaled varieties yielding surprisingly deep rust and burnt sienna tones. Native to the highlands of Mexico and Guatemala, dahlias were cultivated by the Aztecs as a food source (edible tubers) and ornamental plant. As dye flowers, dahlias are exceptionally prolific: a single mature plant can produce dozens of large flower heads throughout summer, providing more dye material per plant than almost any other flower. The flavonoid pigments are moderately lightfast, especially with alum mordant. In the natural dyer's garden, dahlias occupy a unique niche — they bloom continuously from midsummer through first frost, providing fresh dye material during the months when other dye plants have finished their season.", tags: ["Flower", "Orange", "Garden", "Prolific", "Sunset"], regions: ["Mexico (origin)", "Global cultivation"], seasonality: "Flowers Summer through Frost", priceRange: { raw: "$10.00 – $30.00 / kg (dried)", minUSD: 10.0, maxUSD: 30.0, unit: "kg" }, translationCount: 4, typicalMOQ: { quantity: 1, unit: "kg" }, leadTime: { minWeeks: 4, maxWeeks: 8 }, profilePills: { scientificName: "Dahlia Spp.", plantPart: "Flower", handFeel: "N/A", fiberType: "Flower Dye", era: "~1800s", origin: "Mexico" }, seeAlso: [{ id: "marigold" }, { id: "coreopsis" }, { id: "weld" }] }),
  p({ id: "safflower", name: "Safflower", image: "https://res.cloudinary.com/dawxvzlte/image/upload/v1771619521/atlas/lupdbya0hskx16fn738z.jpg", category: "dye", subtitle: "Thistle Flower, Dual Yellow-Red Pigment", about: "Safflower (Carthamus tinctorius) is unique among dye plants in containing two distinct pigments in the same flower: a yellow flavonoid (water-soluble, easily washed out) and a red carthamin (alkali-soluble, precious). Japanese 'beni' dyers developed elaborate techniques over centuries to first wash away the yellow, then extract the prized red by treating the petals with alkaline ash-water. The resulting 'beni' red was used to color kimono silk and produce traditional lip rouge — the most expensive cosmetic in Edo-period Japan. Safflower cultivation dates to at least 3500 BCE in Egypt, where safflower-dyed cloth has been found in pharaonic tombs. The plant is also the source of safflower cooking oil. In traditional Chinese medicine, safflower (hónghuā) is used to improve blood circulation.", tags: ["Flower", "Dual-Pigment", "Red", "Japanese", "Cosmetic"], regions: ["Japan", "India", "Egypt", "China", "Ethiopia"], seasonality: "Flowers Harvested Summer", priceRange: { raw: "$15.00 – $50.00 / kg (dried petals)", minUSD: 15.0, maxUSD: 50.0, unit: "kg" }, translationCount: 8, typicalMOQ: { quantity: 2, unit: "kg" }, leadTime: { minWeeks: 6, maxWeeks: 12 }, profilePills: { scientificName: "Carthamus Tinctorius", plantPart: "Flower", handFeel: "N/A", fiberType: "Flower Dye", era: "~3500 BCE", origin: "Near East" }, seeAlso: [{ id: "madder" }, { id: "cochineal" }, { id: "marigold" }] }),
  p({ id: "elderberry", name: "Elderberry", image: "https://res.cloudinary.com/dawxvzlte/image/upload/v1771743812/atlas/zsdtlskyz16joossntub.jpg", category: "dye", subtitle: "Berry Dye, Soft Lavender to Purple", about: "Elderberry (Sambucus nigra) produces soft lavender, purple, and blue-gray tones from its dark, juice-rich berries — one of the few natural sources of purple that doesn't require a tropical insect or a sea snail. The anthocyanin pigments responsible for the dark purple-black juice produce surprisingly muted, dusty tones on fabric rather than the vivid purple one might expect. With alum mordant, elderberry yields soft lavender on wool; with iron, it shifts to gray-blue and slate. The colors are unfortunately fugitive, fading relatively quickly with washing and light — a common limitation of anthocyanin-based dyes. Despite this, elderberry remains beloved by folk dyers for its accessibility (elder grows wild throughout European hedgerows) and the ethereal, painterly quality of its colors. The berries, flowers, and bark all have long histories in European folk medicine.", tags: ["Berry", "Purple", "Folk", "Accessible", "Anthocyanin"], regions: ["Europe", "North America"], seasonality: "Berries Harvested Late Summer", priceRange: { raw: "$5.00 – $15.00 / kg", minUSD: 5.0, maxUSD: 15.0, unit: "kg" }, translationCount: 4, typicalMOQ: { quantity: 2, unit: "kg" }, leadTime: { minWeeks: 4, maxWeeks: 8 }, profilePills: { scientificName: "Sambucus Nigra", plantPart: "Berry", handFeel: "N/A", fiberType: "Berry Dye", era: "Ancient", origin: "Europe" }, seeAlso: [{ id: "blackberry" }, { id: "avocado-dye" }, { id: "logwood" }] }),
  p({ id: "blackberry", name: "Blackberry", image: "https://res.cloudinary.com/dawxvzlte/image/upload/v1771619529/atlas/o7dlr8jlejkgdxxcviwe.jpg", category: "dye", subtitle: "Berry Dye, Muted Purple-Gray", about: "Blackberry (Rubus spp.) produces surprisingly muted tones — not the vivid purple one might expect from the deeply stained fingers of summer berry-picking, but soft gray-lavenders, dusty mauves, and sage greens that shift with pH and mordant. The anthocyanin pigments in the berries are inherently unstable on fiber, fading and changing color over time in ways that some dyers find charming and others find frustrating. Interestingly, blackberry leaves and shoots (not the fruit) produce more permanent colors: warm tans and grays that are reasonably lightfast. Blackberry dyeing is most popular with foragers and eco-dyers who appreciate the seasonal, ephemeral nature of berry colors. The genus Rubus is extraordinarily widespread, growing wild on every temperate continent — making blackberry one of the most universally available foraged dye materials.", tags: ["Berry", "Purple-Gray", "Foraging", "Wild", "Anthocyanin"], regions: ["Europe", "North America", "Global temperate"], seasonality: "Berries Harvested Late Summer", priceRange: { raw: "Free (foraged)" }, translationCount: 4, typicalMOQ: { quantity: 0, unit: "unit" } /* N/A */, leadTime: { minWeeks: 0, maxWeeks: 0 } /* Immediate */, profilePills: { scientificName: "Rubus Spp.", plantPart: "Berry/Leaf", handFeel: "N/A", fiberType: "Berry Dye", era: "Ancient", origin: "Europe" }, seeAlso: [{ id: "elderberry" }, { id: "avocado-dye" }, { id: "logwood" }] }),
  p({ id: "mushroom-dyes", name: "Mushroom Dyes", image: "https://res.cloudinary.com/dawxvzlte/image/upload/v1771619535/atlas/j6ousox7zxmhqvub8rou.jpg", category: "dye", subtitle: "Fungal Pigments, Earth Spectrum", about: "Mushroom dyeing uses pigments extracted from various fungi to produce an extraordinary range of colors — from bright yellows and oranges to deep purples, greens, and even true reds. The field was pioneered by Miriam Rice in the 1970s in Mendocino County, California, and has since grown into a dedicated community of artist-dyers and mycologists. Over 300 fungal species have been documented as useful dye sources. Dermocybe (Cortinarius) mushrooms produce some of the most vivid and lightfast colors in all of natural dyeing, rivaling synthetic dyes in permanence. Phaeolus schweinitzii (dyer's polypore) yields brilliant gold, while Hapalopilus nidulans produces striking violet. Mushroom dyes require foraging expertise and seasonal awareness, making them among the most specialized natural dyes — but the colors they produce are often impossible to achieve with any other natural source.", tags: ["Fungi", "Pigment", "Art", "Lightfast", "Foraging"], regions: ["Pacific Northwest", "Scandinavia", "Global temperate forests"], seasonality: "Autumn Foraging Season", priceRange: { raw: "$20.00 – $60.00 / kg (dried)", minUSD: 20.0, maxUSD: 60.0, unit: "kg" }, translationCount: 4, typicalMOQ: { quantity: 0, unit: "unit" } /* 0.5 Kg */, leadTime: { minWeeks: 8, maxWeeks: 16 }, profilePills: { scientificName: "Various Fungi", plantPart: "Fruiting Body", handFeel: "N/A", fiberType: "Fungal Dye", era: "Indigenous", origin: "Global" }, seeAlso: [{ id: "madder" }, { id: "ochre" }, { id: "weld" }] }),
  p({ id: "mollusk-purple", name: "Mollusk Purple (Tyrian)", image: "https://res.cloudinary.com/dawxvzlte/image/upload/v1771619540/atlas/pvz6fchtmcubcsgp1v2x.jpg", category: "dye", subtitle: "Sea Snail Mucus, Imperial Purple", about: "Tyrian purple was the most expensive substance in the ancient world — worth more than gold by weight — and approximately 12,000 Bolinus brandaris sea snails were needed to produce just 1.5 grams of dye. The pigment 6,6'-dibromoindigo is extracted from the hypobranchial gland of predatory murex sea snails found in the Mediterranean, and the production process involved fermenting crushed glands in urine for days in open vats — ancient dye works were notorious for their overwhelming stench. The color was reserved for royalty and the highest clergy: Roman senators wore togas with purple borders, and Byzantine emperors were literally 'born in the purple' (porphyrogenitos). Phoenician Sidon and Tyre (modern Lebanon) built their civilization on the purple trade. The chemical compound was only synthesized in 1903, and a few artisan dyers in Lebanon, Tunisia, and Mexico still produce small quantities from wild-harvested mollusks.", tags: ["Mollusk", "Purple", "Imperial", "Ancient", "Rare"], regions: ["Mediterranean (Lebanon", "Tunisia", "Crete)"], seasonality: "Harvested Year-Round (historically)", priceRange: { raw: "Historically priceless" }, translationCount: 6, typicalMOQ: { quantity: 0, unit: "unit" } /* N/A */, leadTime: { minWeeks: 0, maxWeeks: 0 } /* N/A */, profilePills: { scientificName: "Bolinus Brandaris", plantPart: "Hypobranchial Gland", handFeel: "N/A", fiberType: "Animal Dye", era: "~1500 BCE", origin: "Phoenicia (Lebanon)" }, seeAlso: [{ id: "indigo" }, { id: "cochineal" }, { id: "madder" }] }),
  p({ id: "clay-pigments", name: "Clay Pigments", image: "https://res.cloudinary.com/dawxvzlte/image/upload/v1771619543/atlas/n3tolo9qekm94rovwims.jpg", category: "dye", subtitle: "Earth Colors, Ancient Palette", about: "Clay pigments are among the most permanent and lightfast colorants known, with archaeological examples retaining their original color after tens of thousands of years. Different clay compositions produce different colors: kaolin gives white, laterite gives red, bentonite gives gray-green, and manganese-rich clays produce deep brown-black. In West Africa, the Bamana people of Mali developed bògòlanfini (mudcloth) — a sophisticated technique where fermented river mud is painted onto cotton pre-treated with plant tannins, creating the iconic geometric patterns in brown and black. Aboriginal Australians have used ochre-rich clays for body decoration and rock art for at least 65,000 years. Japanese doro-zome (mud dyeing) uses iron-rich mud from specific riverbeds to produce unique brown-black tones on silk. Clay pigments are essentially mineral, making them completely non-toxic, biodegradable, and UV-stable.", tags: ["Mineral", "Earth", "Ancient", "Permanent", "Mud-Cloth"], regions: ["Global (Mali", "Australia", "France", "Italy", "India)"], seasonality: "Available Year-Round", priceRange: { raw: "$2.00 – $8.00 / kg", minUSD: 2.0, maxUSD: 8.0, unit: "kg" }, translationCount: 12, typicalMOQ: { quantity: 10, unit: "kg" }, leadTime: { minWeeks: 2, maxWeeks: 4 }, profilePills: { scientificName: "Various Clays", plantPart: "Mineral", handFeel: "N/A", fiberType: "Earth Pigment", era: "Prehistoric", origin: "Global" }, seeAlso: [{ id: "ochre" }, { id: "iron-oxide" }, { id: "madder" }] }),
  p({ id: "oak-galls", name: "Oak Galls", image: "https://res.cloudinary.com/dawxvzlte/image/upload/v1771619557/atlas/alwppdagqsnqhbphg0ck.jpg", category: "dye", subtitle: "Insect-Induced Tannin, Iron-Gall Black", about: "Oak galls are round growths formed when parasitic wasps (Cynipidae) lay eggs in oak leaf buds, triggering the tree to produce a tannin-rich protective structure. These galls contain an extraordinary 50-70% gallotannin by weight — the highest tannin concentration of any natural material. When combined with iron sulfate and a binder, oak gall tannin produces iron gall ink — the standard writing ink of Western civilization for over 1,500 years. Every important Western document from the Magna Carta to the Declaration of Independence was written in iron gall ink. As a textile dye, oak galls produce warm tans to deep charcoal-black depending on iron concentration. Aleppo galls from Turkey are considered the highest quality, and they remain essential in traditional calligraphy, manuscript conservation, and artisan natural dyeing.", tags: ["Tannin", "Black", "Ink", "Mordant", "Historic"], regions: ["Turkey (Aleppo galls)", "Iran", "Europe"], seasonality: "Harvested Autumn", priceRange: { raw: "$10.00 – $30.00 / kg", minUSD: 10.0, maxUSD: 30.0, unit: "kg" }, translationCount: 6, typicalMOQ: { quantity: 2, unit: "kg" }, leadTime: { minWeeks: 4, maxWeeks: 8 }, profilePills: { scientificName: "Cynips Quercusfolii", plantPart: "Gall/Tannin", handFeel: "N/A", fiberType: "Tannin Source", era: "Ancient", origin: "Middle East / Europe" }, seeAlso: [{ id: "iron-oxide" }, { id: "oak-bark" }, { id: "black-walnut" }] }),
  p({ id: "chlorophyll", name: "Chlorophyll", image: "https://res.cloudinary.com/dawxvzlte/image/upload/v1771828604/atlas/uv7wekjoclf5exxruyri.jpg", category: "dye", subtitle: "Green Plant Pigment, Challenging Dye", about: "True green is the rarest color in natural dyeing — historically achieved only by over-dyeing blue (indigo/woad) with yellow (weld/marigold) in a laborious two-bath process. Chlorophyllin, a water-soluble copper derivative of chlorophyll, offers a direct single-bath path to green, making it a valuable addition to the modern natural dyer's palette. Raw chlorophyll extracted from plants is unstable and fugitive, but the copper-complexed chlorophyllin is significantly more lightfast and can produce colors from bright spring green to deep forest tones. The compound is FDA-approved as a food colorant (E141) and is commercially extracted from alfalfa, nettles, and spinach. While purists debate whether chlorophyllin qualifies as a 'natural' dye given its chemical processing, it fills a genuine gap in the natural color palette that has frustrated dyers for millennia.", tags: ["Green", "Plant", "Challenging", "Chlorophyllin", "Rare-Color"], regions: ["Global"], seasonality: "Year-Round (extracted)", priceRange: { raw: "$15.00 – $40.00 / kg (chlorophyllin)", minUSD: 15.0, maxUSD: 40.0, unit: "kg" }, translationCount: 3, typicalMOQ: { quantity: 1, unit: "kg" }, leadTime: { minWeeks: 4, maxWeeks: 8 }, profilePills: { scientificName: "Chlorophyllin (Cu Complex)", plantPart: "Leaf Extract", handFeel: "N/A", fiberType: "Plant Pigment", era: "Modern", origin: "Global" }, seeAlso: [{ id: "indigo" }, { id: "weld" }, { id: "woad" }] }),
  p({ id: "henna", name: "Henna", image: "https://res.cloudinary.com/dawxvzlte/image/upload/v1771619642/atlas/y3wqh73yyza0ijy66u5g.jpg", category: "dye", subtitle: "Leaf Dye, Sacred Body & Textile Art", about: "Henna (Lawsonia inermis) leaves contain lawsone — a naphthoquinone pigment that bonds permanently to keratin (skin, hair, nails) and protein fibers, producing a characteristic range of orange-brown to deep burgundy. Henna body art (mehndi) is a millennia-old tradition spanning North Africa, the Middle East, and South Asia, where intricate designs are applied to hands and feet for weddings, festivals, and religious celebrations. As a textile dye, henna produces warm terracotta to chocolate brown on wool and silk, with excellent washfastness. The plant thrives in hot, arid climates and has been cultivated in Egypt, India, Morocco, and Sudan for at least 5,000 years — mummies have been found with henna-dyed hair and nails. The night before a South Asian wedding (mehndi ki raat) is entirely dedicated to the ritual application of elaborate henna designs on the bride.", tags: ["Leaf", "Body-Art", "Sacred", "Substantive", "Ancient"], regions: ["India", "Morocco", "Egypt", "Sudan", "Pakistan"], seasonality: "Leaves Harvested Summer", priceRange: { raw: "$5.00 – $20.00 / kg", minUSD: 5.0, maxUSD: 20.0, unit: "kg" }, translationCount: 10, typicalMOQ: { quantity: 5, unit: "kg" }, leadTime: { minWeeks: 4, maxWeeks: 8 }, profilePills: { scientificName: "Lawsonia Inermis", plantPart: "Leaf", handFeel: "N/A", fiberType: "Plant Dye", era: "~5000 years", origin: "North Africa / South Asia" }, seeAlso: [{ id: "madder" }, { id: "turmeric" }, { id: "pomegranate" }] }),
  p({ id: "solar-dyeing", name: "Solar Dyeing", image: "https://res.cloudinary.com/dawxvzlte/image/upload/v1771619579/atlas/couyzdrqyrr399omx6mv.jpg", category: "dye", subtitle: "Sun-Powered Technique, Slow Dye Process", about: "Solar dyeing is a low-energy natural dye technique that uses sunlight to heat a sealed glass jar containing water, fiber, and dye material — essentially a slow, passive extraction that eliminates the need for a stovetop entirely. The method works best during warm, sunny months and typically takes 3-7 days to achieve full color depth, compared to 1-2 hours of conventional simmering. The gentle, prolonged heating can actually produce different color results than stovetop dyeing, as some pigments extract more completely at lower temperatures. Solar dyeing is especially popular in the eco-dye community for its minimal energy footprint and the element of surprise — each jar is a small experiment. The technique pairs naturally with kitchen-waste dyes like avocado, onion skins, and tea, making it an ideal low-investment entry point for sustainable textile craft.", tags: ["Technique", "Solar", "Low-Energy", "Slow", "Accessible"], regions: ["Global"], seasonality: "Best in Summer (strong sun)", priceRange: { raw: "N/A" }, translationCount: 2, typicalMOQ: { quantity: 0, unit: "unit" } /* N/A */, leadTime: { minWeeks: 1, maxWeeks: 4 }, profilePills: { scientificName: "N/A", plantPart: "N/A", handFeel: "N/A", fiberType: "Dye Technique", era: "Modern", origin: "Global" }, seeAlso: [{ id: "avocado-dye" }, { id: "onion-skins" }, { id: "marigold" }] }),
  p({ id: "tie-dye", name: "Tie-Dye", image: "https://res.cloudinary.com/dawxvzlte/image/upload/v1771619575/atlas/rhdui5rkwvsnxbknnntj.jpg", category: "dye", subtitle: "Bound Resist, Counterculture Icon", about: "Tie-dye is a resist-dyeing technique most associated with the American counterculture of the 1960s-70s, but the underlying method — binding, knotting, or clamping cloth to prevent dye penetration — is ancient and nearly universal. Indian bandhani (tie-resist on fine silk and cotton) dates to 4000 BCE and involves tying thousands of tiny points with thread to create intricate dot patterns. Nigerian adire oniko uses raffia to tie indigo-resist patterns on cotton. Japanese kanoko shibori is a refined form of tie-dyeing that produces precise, repeatable patterns. The American counterculture appropriated and simplified these techniques, combining them with synthetic fiber-reactive dyes on cotton to produce the iconic rainbow spiral. Tie-dye experienced major commercial revivals in the 1990s and again during the 2020 pandemic, when homebound crafters embraced it as an accessible creative outlet.", tags: ["Technique", "Resist", "Counterculture", "American", "Revival"], regions: ["USA", "India", "West Africa", "Japan", "Global"], seasonality: "Year-Round Practice", priceRange: { raw: "Varies" }, translationCount: 8, typicalMOQ: { quantity: 0, unit: "unit" } /* N/A */, leadTime: { minWeeks: 0, maxWeeks: 0 } /* Variable */, profilePills: { scientificName: "N/A", plantPart: "N/A", handFeel: "N/A", fiberType: "Dye Technique", era: "Ancient / 1960s Revival", origin: "Global" }, seeAlso: [{ id: "shibori" }, { id: "batik" }, { id: "indigo" }] }),
];
/* ── BATCH 3b — ADDITIONAL TEXTILE TECHNIQUES ── */
const textileProfilesB: FiberProfile[] = [
  p({ id: "spinning", name: "Spinning", image: "https://res.cloudinary.com/dawxvzlte/image/upload/v1771619312/atlas/m2gfnb0ypgvtzixvinxt.jpg", category: "textile", subtitle: "Fiber to Yarn, Foundation of Textiles", about: "Spinning is the fundamental technology that makes all woven, knitted, and crocheted textiles possible — the act of drawing out and twisting short fibers into a continuous, strong yarn. The oldest evidence of spun fiber dates to approximately 30,000 years ago (twisted plant fibers from Dzudzuana Cave, Georgia). The drop spindle, humanity's first spinning tool, remained the primary method for at least 9,000 years before the spinning wheel appeared in India around 500 CE and spread to Europe by the 13th century. The spinning jenny (1764), water frame (1769), and spinning mule (1779) triggered the Industrial Revolution — arguably the most transformative technological shift in human history, beginning with yarn. Modern ring spinning, rotor (open-end) spinning, and air-jet spinning produce yarn at speeds unimaginable to hand spinners, but a growing community of hand spinners worldwide maintains the ancient craft for its meditative qualities and artistic possibilities.", tags: ["Yarn", "Foundation", "Ancient", "Technology", "Industrial-Revolution"], regions: ["Global"], seasonality: "Year-Round", priceRange: { raw: "N/A" }, translationCount: 10, typicalMOQ: { quantity: 0, unit: "unit" } /* N/A */, leadTime: { minWeeks: 0, maxWeeks: 0 } /* Variable */, profilePills: { scientificName: "N/A", plantPart: "N/A", handFeel: "N/A", fiberType: "Yarn Technology", era: "~8000 BCE", origin: "Global" }, seeAlso: [{ id: "wool" }, { id: "organic-cotton" }, { id: "flax-linen" }] }),
  p({ id: "cable-knit", name: "Cable Knit", image: "https://res.cloudinary.com/dawxvzlte/image/upload/v1771619350/atlas/xbyvbhkqvsoodplxb8de.jpg", category: "textile", subtitle: "Aran Islands, Crossed-Stitch Texture", about: "Cable knitting is a technique that creates twisted, rope-like patterns by crossing groups of stitches over each other, producing raised, three-dimensional textures on the fabric surface. The style is most associated with the Aran Islands off the west coast of Ireland, where fishermen's sweaters (ganseys) featured elaborate cable patterns that — according to popular legend — identified the wearer's family or village. While this romantic notion has been largely debunked by textile historians, Aran cable knitting remains one of the most iconic textile traditions in the world. The technique requires a cable needle to temporarily hold stitches while others cross behind or in front. Common cable variants include rope cable, honeycomb, diamond, and the complex 'Tree of Life' pattern. Cable knitting uses approximately 30% more yarn than stockinette, creating a denser, warmer, and more wind-resistant fabric.", tags: ["Knit", "Irish", "Aran", "Textured", "Heritage"], regions: ["Ireland", "Scotland", "Scandinavia", "Global"], seasonality: "Year-Round Practice", priceRange: { raw: "Varies" }, translationCount: 4, typicalMOQ: { quantity: 0, unit: "unit" } /* N/A */, leadTime: { minWeeks: 0, maxWeeks: 0 } /* Variable */, profilePills: { scientificName: "N/A", plantPart: "N/A", handFeel: "Textured", fiberType: "Knit Structure", era: "~1800s", origin: "Aran Islands, Ireland" }, seeAlso: [{ id: "wool" }, { id: "merino" }, { id: "felt" }] }),
  p({ id: "dobby", name: "Dobby Weave", image: "https://res.cloudinary.com/dawxvzlte/image/upload/v1771619335/atlas/ia0ujj85h7nbtwjhpzvm.jpg", category: "textile", subtitle: "Small-Pattern Weave, Geometric Texture", about: "Dobby weave creates small, geometric patterns woven into the fabric structure using a dobby mechanism — a simplified alternative to the Jacquard that controls groups of warp threads rather than individual ones. The name derives from 'dobby boy,' the child who sat atop traditional draw looms and lifted warp threads on command. Dobby patterns include dots, small diamonds, geometric stripes, honeycomb textures, and piqué effects. The mechanism typically controls 16-40 shafts, producing patterns smaller and simpler than Jacquard but more complex than basic twill or plain weave. Dobby fabrics appear everywhere in modern textiles: Oxford shirting, waffle weave towels, bird's-eye diaper cloth, and piqué polo shirts are all dobby weaves. The structure adds visual and tactile interest without the cost of Jacquard weaving, making it the workhorse of mid-range figured textiles.", tags: ["Weave", "Geometric", "Figured", "Automated", "Versatile"], regions: ["Global"], seasonality: "Year-Round Production", priceRange: { raw: "Varies" }, translationCount: 4, typicalMOQ: { quantity: 0, unit: "unit" } /* Varies */, leadTime: { minWeeks: 0, maxWeeks: 0 } /* Variable */, profilePills: { scientificName: "N/A", plantPart: "N/A", handFeel: "Textured", fiberType: "Figured Weave", era: "~1800s", origin: "England" }, seeAlso: [{ id: "jacquard" }, { id: "twill" }, { id: "plain-weave" }] }),
  p({ id: "muslin", name: "Muslin", image: "https://res.cloudinary.com/dawxvzlte/image/upload/v1771619419/atlas/rg8eyy0xhjyni7qwh7qv.jpg", category: "textile", subtitle: "Finest Cotton Weave, Bangladeshi Heritage", about: "Muslin is an ultra-fine, gossamer-light plain-weave cotton fabric that originated in Dhaka, Bangladesh, where Mughal emperors called it 'woven air' (ab-e-rawan) and 'running water' for its ethereal translucency. The finest Dhaka muslins were woven from a now-extinct cotton variety called Phuti Karpas, spun to thread counts so fine that an entire sari could pass through a finger ring. British colonial policy deliberately destroyed the Bengali muslin industry in the 18th-19th centuries to create a captive market for Lancashire cotton — a devastating act of industrial sabotage. The master weavers' skills were lost for generations, though a revival project by the Bangladesh government has partially recreated heritage muslin using wild cotton descendants. Today 'muslin' commercially refers to any lightweight plain-weave cotton, but the original Dhaka muslin was incomparably finer — a lost textile art that represented the absolute pinnacle of hand-spinning and hand-weaving achievement.", tags: ["Cotton", "Ultra-Fine", "Bengali", "Heritage", "Lost-Art"], regions: ["Bangladesh (Dhaka)", "India", "Global"], seasonality: "Year-Round Production", priceRange: { raw: "$20.00 – $500.00 / m (heritage grade)", unit: "m" }, translationCount: 6, typicalMOQ: { quantity: 10, unit: "m" }, leadTime: { minWeeks: 8, maxWeeks: 16 }, profilePills: { scientificName: "Gossypium (Fine Cotton)", plantPart: "N/A", handFeel: "Gossamer", fiberType: "Fine Plain Weave", era: "~700 CE", origin: "Dhaka, Bengal" }, seeAlso: [{ id: "organic-cotton" }, { id: "plain-weave" }, { id: "silk" }] }),
  p({ id: "flannel", name: "Flannel", image: "https://res.cloudinary.com/dawxvzlte/image/upload/v1771660234/atlas/jppbfietovs2kr5pjnir.jpg", category: "textile", subtitle: "Brushed Fabric, Welsh Origins", about: "Flannel is a soft, warm fabric with a slightly napped surface created by brushing or raising the fibers after weaving, trapping air for insulation. Originating in Wales in the 16th-17th century, flannel was originally woven from carded wool and became the fabric of Welsh mining and farming communities. The name may derive from the Welsh 'gwlanen' (woolen cloth). Cotton flannel emerged in the 19th century and became the material of choice for American workwear shirts — the iconic 'flannel shirt' of lumberjacks, loggers, and eventually grunge musicians. Flannel can be woven in plain or twill weave; the defining characteristic is the napped finish rather than the weave structure. Baby flannel (flannelette) is a lightweight cotton variety, while wool flannel remains the standard for quality suiting and trousers. The fabric's association with both rugged workwear and comfortable sleepwear makes it one of the most culturally versatile textiles.", tags: ["Brushed", "Warm", "Welsh", "Workwear", "Napped"], regions: ["Wales", "Scotland", "USA", "Global"], seasonality: "Year-Round Production", priceRange: { raw: "$5.00 – $20.00 / m", unit: "m" }, translationCount: 4, typicalMOQ: { quantity: 100, unit: "m" }, leadTime: { minWeeks: 4, maxWeeks: 8 }, profilePills: { scientificName: "N/A", plantPart: "N/A", handFeel: "Soft Napped", fiberType: "Brushed Weave", era: "~1600s", origin: "Wales" }, seeAlso: [{ id: "wool" }, { id: "denim" }, { id: "twill" }] }),
  p({ id: "block-print", name: "Block Printing", image: "https://res.cloudinary.com/dawxvzlte/image/upload/v1771619651/atlas/dxneiijpebu9cqqvnxfj.jpg", category: "textile", subtitle: "Hand-Carved Stamps, Indian Heritage", about: "Block printing is one of the oldest forms of textile printing, with roots stretching back at least 5,000 years in the Indus Valley civilization. The technique involves carving a design in relief on a wooden block, dipping it in dye paste, and pressing it onto cloth — repeating the stamp across the entire fabric surface with precise alignment. In Rajasthan, India, the tradition is most alive: Jaipur's blue pottery-inspired prints, Sanganer's delicate floral patterns, and Bagru's bold geometric designs each represent distinct regional schools. Master block carvers (chhipas) spend years learning to carve intricate teak or sheesham wood blocks with nail-head details as fine as 1mm. A single fabric may require 14+ different blocks for different colors and pattern elements, each hand-stamped in precise registration. Japanese woodblock printing (katazome), European block printing, and African adinkra stamping developed as parallel traditions.", tags: ["Print", "Hand-Carved", "Indian", "Heritage", "Rajasthani"], regions: ["India (Rajasthan", "Gujarat)", "Japan", "Iran", "Europe"], seasonality: "Year-Round Practice", priceRange: { raw: "$10.00 – $50.00 / m", unit: "m" }, translationCount: 6, typicalMOQ: { quantity: 50, unit: "m" }, leadTime: { minWeeks: 4, maxWeeks: 10 }, profilePills: { scientificName: "N/A", plantPart: "N/A", handFeel: "Varies", fiberType: "Surface Print", era: "~3000 BCE", origin: "India / China" }, seeAlso: [{ id: "batik" }, { id: "indigo" }, { id: "organic-cotton" }] }),
  p({ id: "leno-weave", name: "Leno Weave", image: "https://res.cloudinary.com/dawxvzlte/image/upload/v1771619672/atlas/ywiwxtgbeos81eqcsj7i.webp", category: "textile", subtitle: "Crossed-Warp, Open Gauze Structure", about: "Leno weave creates a stable, open fabric that resists shifting even at very low thread counts by twisting pairs of warp threads around each other between each weft insertion, locking the threads in place. This crossed-warp structure distinguishes leno from plain weave, which would produce an unstable, easily distorted fabric at the same low thread counts. The technique was used in ancient Egypt for fine gauze bandages (mummy wrappings are often leno weave) and in Peru for open-mesh textiles dating to 3000 BCE. Modern leno weaves include marquisette (sheer curtain fabric), gauze bandages, produce bags, and mosquito netting. The structure allows maximum air circulation while maintaining fabric integrity, making it ideal for hot-climate garments and window treatments. Leno can be combined with plain weave areas in the same fabric to create 'lappet' effects — sheer and opaque zones in alternation.", tags: ["Weave", "Open", "Gauze", "Crossed-Warp", "Sheer"], regions: ["Global"], seasonality: "Year-Round Production", priceRange: { raw: "Varies" }, translationCount: 4, typicalMOQ: { quantity: 0, unit: "unit" } /* Varies */, leadTime: { minWeeks: 0, maxWeeks: 0 } /* Variable */, profilePills: { scientificName: "N/A", plantPart: "N/A", handFeel: "Open Sheer", fiberType: "Gauze Weave", era: "Ancient", origin: "Egypt / Peru" }, seeAlso: [{ id: "plain-weave" }, { id: "silk" }, { id: "flax-linen" }] }),
];
/* ── BATCH 3b — ADDITIONAL FIBER VARIANTS ── */
const fiberVariantsB: FiberProfile[] = [
  p({ id: "rambouillet", name: "Rambouillet", image: "https://res.cloudinary.com/dawxvzlte/image/upload/v1771727450/atlas/avyjf3tsczjo6b6zpyv6.jpg", category: "fiber", subtitle: "French Royal Merino, Fine American Wool", about: "The Rambouillet breed descends from Spanish Merinos imported to the royal estate at Rambouillet, France, in 1786 under the patronage of Louis XVI. Selectively bred for over two centuries, Rambouillet sheep produce a dense, fine wool (18-24 microns) with exceptional crimp and elasticity — characteristics that make it virtually interchangeable with Merino in high-end textile applications. The breed was introduced to the American West in the mid-19th century, where its hardiness and herding instinct made it the foundation of the range sheep industry. Today, Rambouillet bloodlines constitute roughly 50% of all American sheep. The wool's high lanolin content (25-45%) provides natural weatherproofing on the animal and yields valuable lanolin as a processing byproduct. Rambouillet fiber is prized by hand spinners for its consistent staple length, memory, and the way it blooms after washing into a lofty, resilient yarn.", tags: ["Wool", "Fine", "French", "American", "Range"], regions: ["France", "USA (Western states)", "South America"], seasonality: "Sheared Spring", priceRange: { raw: "$8.00 – $25.00 / kg", minUSD: 8.0, maxUSD: 25.0, unit: "kg" }, translationCount: 3, typicalMOQ: { quantity: 50, unit: "kg" }, leadTime: { minWeeks: 8, maxWeeks: 14 }, profilePills: { scientificName: "Ovis Aries (Rambouillet)", plantPart: "Fleece", handFeel: "Fine Elastic", fiberType: "Fine Wool", era: "~1800s", origin: "France" }, seeAlso: [{ id: "merino" }, { id: "wool" }, { id: "columbia" }] }),
  p({ id: "acetate", name: "Acetate", image: "https://images.unsplash.com/photo-1718587608491-f40ae3b13273?crop=entropy&cs=tinysrgb&fit=max&fm=jpg&ixid=M3w3Nzg4Nzd8MHwxfHNlYXJjaHwxfHxhY2V0YXRlJTIwZmFicmljJTIwc2hpbnklMjBzYXRpbiUyMGxpbmluZ3xlbnwxfHx8fDE3NzMwMTc3ODl8MA&ixlib=rb-4.1.0&q=80&w=1080", category: "textile", subtitle: "Semi-Synthetic, Silk-Like Drape", about: "Acetate is a semi-synthetic fiber made by treating wood pulp or cotton linters with acetic acid and acetic anhydride, producing cellulose acetate — the first thermoplastic fiber. Unlike viscose rayon (which regenerates pure cellulose), acetate retains its acetyl groups, giving it distinctly different properties: a silk-like luster and drape, excellent color vibrancy, and resistance to shrinking and wrinkling. Developed commercially in the 1920s by Celanese Corporation, acetate became the standard lining fabric for suits, coats, and evening wear — a role it largely retains today. The fiber is also used in cigarette filters, eyeglass frames (cellulose acetate), and photographic film. Acetate's main limitations are low heat resistance (it melts under a hot iron), poor moisture absorption, and susceptibility to nail polish remover (acetone dissolves it). Triacetate, a fully acetylated variant, offers improved heat resistance and washability.", tags: ["Semi-Synthetic", "Cellulose", "Silk-Like", "Lining", "Thermoplastic"], regions: ["USA", "UK", "Germany", "Japan", "China"], seasonality: "Year-Round Production", priceRange: { raw: "$3.00 – $8.00 / kg", minUSD: 3.0, maxUSD: 8.0, unit: "kg" }, translationCount: 3, typicalMOQ: { quantity: 500, unit: "kg" }, leadTime: { minWeeks: 4, maxWeeks: 8 }, profilePills: { scientificName: "Cellulose Acetate", plantPart: "Pulp", handFeel: "Silky", fiberType: "Semi-Synthetic", era: "~1920s", origin: "Switzerland / UK" }, seeAlso: [{ id: "viscose-rayon" }, { id: "cupro" }, { id: "silk" }] }),
  p({ id: "water-lily", name: "Water Lily Fiber", image: "https://res.cloudinary.com/dawxvzlte/image/upload/v1771619707/atlas/adjrgltq6pg5p0zpahzq.jpg", category: "fiber", subtitle: "Aquatic Stem Fiber, Rare Textile", about: "Water lily fiber is extracted from the stems of Nymphaea species using a process nearly identical to lotus silk production. Artisans on Inle Lake in Myanmar discovered that water lily stems, like lotus, contain fine silk-like filaments that can be drawn out by snapping the stem and gently pulling the broken ends apart. Each stem yields only 20-30 hair-thin threads, making production extraordinarily labor-intensive — a single scarf may require 9,000 or more stems and weeks of patient hand-work. The resulting fabric has a texture between raw silk and fine linen, with a subtle natural luster and excellent breathability. Water lily fiber is even rarer than lotus silk, produced by only a handful of artisan families who guard the technique as hereditary knowledge. The fabric is primarily used for monastic robes and ceremonial textiles in Myanmar and Cambodia.", tags: ["Aquatic", "Rare", "Sacred", "Myanmar", "Hand-Extracted"], regions: ["Myanmar (Inle Lake)", "Cambodia", "Vietnam"], seasonality: "Harvested Year-Round", priceRange: { raw: "$200.00 – $1,000.00 / m", unit: "m" }, translationCount: 3, typicalMOQ: { quantity: 1, unit: "m" }, leadTime: { minWeeks: 20, maxWeeks: 52 }, profilePills: { scientificName: "Nymphaea Spp.", plantPart: "Stem", handFeel: "Silk-Linen", fiberType: "Aquatic Fiber", era: "Ancient", origin: "Myanmar" }, seeAlso: [{ id: "lotus" }, { id: "silk" }, { id: "peace-silk" }] }),
  p({ id: "sano", name: "Sano (Allo/Himalayan Nettle)", image: "https://res.cloudinary.com/dawxvzlte/image/upload/v1771619710/atlas/prcrmaajzda7je3tkp2j.jpg", category: "fiber", subtitle: "Himalayan Giant Nettle, Nepali Heritage", about: "Sano (or allo) is a bast fiber extracted from the Himalayan giant nettle (Girardinia diversifolia), a plant that grows wild at elevations of 1,200-3,000 meters across Nepal, Bhutan, and Northeast India. Unlike European stinging nettle, the Himalayan giant nettle can reach heights of 3 meters, yielding much longer and stronger fibers. Processing is arduous: bark is stripped from the stalks, boiled in ash-water for hours, beaten with mallets, washed in running streams, and hand-spun on drop spindles — a process unchanged for centuries. The resulting fiber resembles linen in strength and drape but with a slightly rougher hand that softens beautifully with washing. Allo cloth is central to the culture of the Rai and Magar ethnic groups of eastern Nepal, where it is woven into carrying bags (jhola), fishing nets, and clothing. NGOs are now working with Nepali communities to develop allo as a sustainable export fiber.", tags: ["Nettle", "Himalayan", "Indigenous", "Heritage", "Sustainable"], regions: ["Nepal", "Bhutan", "Northeast India"], seasonality: "Bark Harvested Autumn", priceRange: { raw: "$15.00 – $40.00 / kg", minUSD: 15.0, maxUSD: 40.0, unit: "kg" }, translationCount: 4, typicalMOQ: { quantity: 10, unit: "kg" }, leadTime: { minWeeks: 10, maxWeeks: 16 }, profilePills: { scientificName: "Girardinia Diversifolia", plantPart: "Bark", handFeel: "Linen-Like", fiberType: "Bast Fiber", era: "Ancient", origin: "Nepal" }, seeAlso: [{ id: "nettle" }, { id: "hemp" }, { id: "ramie" }] }),
  p({ id: "river-reed", name: "River Reed", image: "https://res.cloudinary.com/dawxvzlte/image/upload/v1771619712/atlas/uq7pryglvmm4qirmei3f.jpg", category: "fiber", subtitle: "Wetland Fiber, Mat & Basket Weaving", about: "River reeds (Phragmites and Typha species) have been woven into mats, baskets, screens, and roofing material across virtually every culture with access to freshwater wetlands — making reed weaving one of the most universal human crafts. Archaeological evidence of reed mats dates to at least 7,000 BCE in the Middle East. Phragmites australis (common reed) can grow up to 4 meters tall and forms dense stands along rivers, lakes, and estuaries on every continent except Antarctica. The stems are harvested in late summer when fully grown, dried in upright bundles, then soaked before weaving to restore flexibility. Reed thatch remains a living roofing tradition in England, the Netherlands, and Japan, while woven reed screens (sudare) are an essential element of Japanese architecture. In the Mesopotamian Marshes of southern Iraq, the Ma'dan people build entire floating villages from bundled Phragmites reeds.", tags: ["Wetland", "Mat", "Basketry", "Universal", "Ancient"], regions: ["Global (all wetland regions)"], seasonality: "Harvested Late Summer/Autumn", priceRange: { raw: "$0.50 – $3.00 / kg", minUSD: 0.5, maxUSD: 3.0, unit: "kg" }, translationCount: 15, typicalMOQ: { quantity: 500, unit: "kg" }, leadTime: { minWeeks: 4, maxWeeks: 6 }, profilePills: { scientificName: "Phragmites / Typha", plantPart: "Stem", handFeel: "Stiff", fiberType: "Reed Fiber", era: "Prehistoric", origin: "Global" }, seeAlso: [{ id: "seagrass" }, { id: "sweetgrass" }, { id: "krajood" }] }),
];

